import React from 'react';

const PropertyCard = ({ property }) => {
  return (
    <div className="min-w-[300px] bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-md transition duration-300">
      {/* Imagen Principal */}
      <div className="h-48 w-full relative">
        <img 
          src={property.image} 
          alt={property.title} 
          className="w-full h-full object-cover"
        />
        <div className="absolute top-3 left-3 bg-blue-600 text-white text-[10px] font-bold px-2 py-1 rounded uppercase">
          {property.tags[0]}
        </div>
      </div>

      {/* Datos Básicos */}
      <div className="p-5">
        <h3 className="text-lg font-bold text-slate-800 leading-tight mb-2 truncate">
          {property.title}
        </h3>
        <p className="text-blue-600 font-bold text-xl mb-4">
          {property.price}
        </p>
        
        <div className="flex justify-between text-slate-500 text-xs border-t pt-4 mb-4">
          <span className="flex items-center gap-1">🛏️ {property.beds}</span>
          <span className="flex items-center gap-1">🚿 {property.baths}</span>
          <span className="flex items-center gap-1">📐 {property.area}</span>
        </div>

        {/* Botón de Interacción */}
        <button className="w-full bg-slate-900 text-white text-sm font-semibold py-2 rounded-lg hover:bg-slate-800 transition">
          Ver detalles y fotos
        </button>
      </div>
    </div>
  );
};

export default PropertyCard;
